const raw = $input.first().json;
const body = raw.body || raw;
if (!body.competitor_name || !body.our_product_name) {
  throw new Error('competitor_name and our_product_name are required');
}
return [{ json: {
  competitor_name: String(body.competitor_name).trim(),
  competitor_category: String(body.competitor_category || 'unknown').trim(),
  our_product_name: String(body.our_product_name).trim(),
  our_strengths: Array.isArray(body.our_strengths) ? body.our_strengths : [],
  our_weaknesses: Array.isArray(body.our_weaknesses) ? body.our_weaknesses : [],
  competitor_claims: Array.isArray(body.competitor_claims) ? body.competitor_claims : [],
  known_objections: Array.isArray(body.known_objections) ? body.known_objections : [],
  recent_changes: Array.isArray(body.recent_changes) ? body.recent_changes : [],
  target_segment: String(body.target_segment || 'all segments').trim(),
  run_id: body.run_id || `bc_${Date.now()}`
} }];

const d = $input.first().json;
const system = `You are a sales enablement expert. You write clear, honest battlecards that help sales reps win deals — not marketing fluff. Use only facts provided. Identify where our product genuinely wins and where it does not. Return ONLY valid JSON.`;
const user = `Create a sales battlecard for ${d.our_product_name} competing against ${d.competitor_name} in the ${d.competitor_category} market.

Target segment: ${d.target_segment}

Our strengths: ${d.our_strengths.join('; ')}
Our weaknesses: ${d.our_weaknesses.join('; ')}
Competitor claims: ${d.competitor_claims.join('; ')}
Known objections from prospects: ${d.known_objections.join('; ')}
Competitor recent changes: ${d.recent_changes.join('; ')}

Return JSON:
{
  "headline": "string — one sentence win thesis",
  "when_we_win": [{ "situation": "string", "reason": "string" }],
  "when_we_lose": [{ "situation": "string", "reason": "string" }],
  "objection_handling": [{ "objection": "string", "response": "string", "avoid_saying": "string" }],
  "discovery_questions": ["string — question to ask prospect to surface our advantage"],
  "landmines": ["string — question to plant that exposes competitor weakness"],
  "claims_rebuttal": [{ "their_claim": "string", "our_response": "string", "evidence": "string" }],
  "recent_changes_impact": "string — what their recent moves mean for deals",
  "confidence": "low|medium|high",
  "confidence_rationale": "string"
}`;
return [{ json: { ...d, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Battlecard Prompt').first().json;
let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No LLM content');
  parsed = JSON.parse(content);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
const req = ['headline','when_we_win','when_we_lose','objection_handling','discovery_questions'];
const missing = req.filter(k => !parsed[k]);
if (missing.length) return [{ json: { _error: true, reason: `Missing: ${missing.join(',')}` } }];
return [{ json: { _error: false, battlecard: parsed, meta: { competitor: upstream.competitor_name, product: upstream.our_product_name, run_id: upstream.run_id, generated_at: new Date().toISOString() } } }];
